const merged = $input.first().json;

return {
  json: {
    ...merged,
    db_order_id: merged.body.order_id,
    db_customer_name: merged.body.customer.name,
    db_customer_email: merged.body.customer.email,
    db_customer_phone: merged.body.customer.phone || '',
    db_customer_city: merged.body.customer.city || '',
    db_customer_county: merged.body.customer.county || '',
    db_cart_json: JSON.stringify(merged.body.items),
    db_subtotal_cents: merged.body.subtotal_cents,
    db_tax_cents: merged.body.tax_cents,
    db_total_cents: merged.body.frontend_total_cents,
    db_square_payment_link: merged.payment_link?.url || merged.payment_link?.long_url || '',
    db_square_order_id: merged.order_id || '',
    db_notes: merged.body.notes || '',
    db_status: 'pending'
  }
};

const merged = $input.first().json;

const paymentLink = merged.payment_link || {};
const squareLink = paymentLink.url || paymentLink.long_url || '';

return {
  json: {
    ok: true,
    message: 'Order received! Check your email for payment link.',
    square_link: squareLink,
    order_id: merged.body.order_id || '',
    total_cents: merged.body.frontend_total_cents || 0
  }
};

// Return error response
return {
  json: {
    ok: false,
    error: 'Invalid order data. Please check your cart and try again.'
  }
};
